const c={generateKey(e){if(e.phone){const n=e.phone.replace(/\D/g,"");if(n.length>=7)return`phone-${n}`}if(e.email)return`email-${e.email.trim().toLowerCase()}`;const t=(e.name||"").trim().toLowerCase().replace(/[^a-z0-9]/g,""),r=(e.city||"").trim().toLowerCase().replace(/[^a-z0-9]/g,"");return`name-city-${t}-${r}`},filterDuplicates(e){const t=new Map;return e.forEach(r=>{const n=this.generateKey(r),o=t.get(n);(!o||(r.relevanceScore||0)>(o.relevanceScore||0))&&t.set(n,r)}),Array.from(t.values())}};export{c as d};
